// ──────────────────────────────────────────────
// Sherlock: 构建事实核查 Prompt
// 输入: Owl 原始数据 + Newton 草稿
// 核心任务: 比对两边的关键信息是否一致
// ──────────────────────────────────────────────

const input = $input.first().json;

const systemPrompt = `你是 「Sherlock 事实核查员」，Nexus Hub 的质量守门人。

## 你的职责
逐个检查文章中的每一条事实性陈述，与原始资讯进行严格比对。

## 判定标准
1. **数值幻觉**: 文章中的数字、百分比、日期是否与原文一致
2. **名称幻觉**: 机构名、人名、专有名词是否准确
3. **因果幻觉**: 推论逻辑是否在原文中有依据
4. **编造幻觉**: 是否出现了原文完全没有的信息

## 输出格式
请 **只返回 JSON**，不要有任何额外文本：
{
  "pass": true/false,
  "issues": [
    { "claim": "文章中的陈述", "source": "原文中的对应数据", "severity": "high/medium/low" }
  ],
  "summary": "一句话总结核查结果"
}

- 如果 pass=true，表示文章准确无误，可以发布
- 如果 pass=false，列出所有问题以便修正`;

const userMessage = `请核查以下文章的事实准确性。

## 原始资讯 (Owl 来源)
${input._owl_raw_body || input._owl_source || '无原始数据'}

## 待核查文章 (Newton 草稿)
${input._newton_draft || input.content || '无草稿'}

请逐条比对并返回 JSON 判定。`;

return {
  model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
  temperature: 0,
  max_tokens: 2048,
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userMessage }
  ]
};

// ──────────────────────────────────────────────
// Sherlock: 解析核查结果并提取判定
// ──────────────────────────────────────────────

const response = $input.first().json;
const rawContent = response.choices?.[0]?.message?.content || '{}';

// 尝试从回复中提取 JSON
let verdict;
try {
  // 处理可能的 markdown 代码块包裹
  const jsonMatch = rawContent.match(/```(?:json)?\s*([\s\S]*?)\s*```/) || [null, rawContent];
  verdict = JSON.parse(jsonMatch[1].trim());
} catch {
  // 如果解析失败，尝试直接解析
  try {
    verdict = JSON.parse(rawContent);
  } catch {
    verdict = { pass: false, issues: [{ claim: '解析失败', source: '', severity: 'high' }], summary: rawContent };
  }
}

// 携带原始数据传递给下一个节点
const prevData = $('🔬 构建核查 Prompt').first().json;

return {
  ...prevData,  // 保留 Newton 草稿和 Owl 原始数据
  _verdict: verdict,
  _sherlock_pass: verdict.pass === true,
  _sherlock_issues: verdict.issues || [],
  _sherlock_summary: verdict.summary || ''
};

// ──────────────────────────────────────────────
// Sherlock 修正路由: 将草稿打回 Newton 重写
// 输出: 附有修正指示的新 Prompt
// ──────────────────────────────────────────────

const data = $input.first().json;
const issues = data._sherlock_issues || [];
const issuesText = issues.map((i, idx) =>
  `${idx + 1}. [${i.severity}] ${i.claim}\n   原文依据: ${i.source}`
).join('\n');

return {
  ...data,
  _retry_count: (data._retry_count || 0) + 1,
  _correction_prompt: `⚠️ Sherlock 发现了以下事实性问题，请修正后重新提交：\n\n${issuesText}\n\n请保持原有的写作风格和格式，只修正事实性错误。`
};

// ──────────────────────────────────────────────
// Sherlock 通过: 附加核查签章
// ──────────────────────────────────────────────

const data = $input.first().json;

// 在文章末尾追加核查签章
const signedContent = (data._newton_draft || data.content || '') +
  `\n\n---\n> ✅ 本文已通过 Sherlock 事实核查 (${new Date().toISOString().slice(0, 10)})`;

return {
  ...data,
  content: signedContent,
  _sherlock_verified: true,
  _verified_at: new Date().toISOString()
};
